    bool equalFrequency(string word) {
        unordered_map<char, int> freq;
        for (char c : word) {
            freq[c]++;
        }
        for (char c : word) {
            freq[c]--;
            bool ok = true;
            for (auto p : freq) {
                if (p.second > 0) {
                    ok = false;
                    break;
                }
            }
            if (ok) return true;
            freq[c]++;
        }
        return false;
    }
};```
